import { StockItem, ID } from '../types';
import { storageService } from './storageService';
import { initialStock } from '../data/wines';
import { generateId } from '../utils/idGenerator';

const STOCK_KEY = 'stock';

const mockAsync = <T>(data: T): Promise<T> => {
    return new Promise((resolve) => setTimeout(() => resolve(data), 50));
};

const getStock = async (): Promise<StockItem[]> => {
    return mockAsync(storageService.getItem<StockItem[]>(STOCK_KEY, initialStock));
};

const saveStockLocal = (stock: StockItem[]): void => {
    storageService.setItem(STOCK_KEY, stock);
};

const addWine = async (newWine: Omit<StockItem, 'id'>): Promise<StockItem> => {
    const newStockItem: StockItem = {
        ...newWine,
        id: generateId(),
    };
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const updatedStock = [...stock, newStockItem];
    saveStockLocal(updatedStock);
    return mockAsync(newStockItem);
};

const updateItem = async (item: StockItem): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const updatedStock = stock.map(s => s.id === item.id ? item : s);
    saveStockLocal(updatedStock);
    return mockAsync(undefined);
};

const updateStock = async (updatedStock: StockItem[]): Promise<void> => {
    saveStockLocal(updatedStock);
    return mockAsync(undefined);
};

const deleteWine = async (id: ID): Promise<void> => {
    let stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    stock = stock.filter(item => item.id !== id);
    saveStockLocal(stock);
    return mockAsync(undefined);
};

const addStockQuantity = async (id: ID, quantityToAdd: number): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const itemIndex = stock.findIndex(item => item.id === id);
    if (itemIndex > -1) {
        stock[itemIndex].quantity += quantityToAdd;
        saveStockLocal(stock);
    }
    return mockAsync(undefined);
};

const removeStockQuantity = async (id: ID, quantityToRemove: number): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const itemIndex = stock.findIndex(item => item.id === id);
    if (itemIndex > -1) {
        const newQuantity = stock[itemIndex].quantity - quantityToRemove;
        stock[itemIndex].quantity = Math.max(0, newQuantity);
        saveStockLocal(stock);
    }
    return mockAsync(undefined);
};

export const stockService = {
    getStock,
    addWine,
    updateItem,
    updateStock,
    deleteWine,
    addStockQuantity,
    removeStockQuantity,
};

import { TransferLog } from '../types';
import { storageService } from './storageService';
import { transferHistory as initialHistory } from '../data/dashboardData';
import { generateId } from '../utils/idGenerator';

const HISTORY_KEY = 'transferHistory';

const mockAsync = <T>(data: T): Promise<T> => {
    return new Promise((resolve) => setTimeout(() => resolve(data), 50));
};

const getTransferHistory = async (): Promise<TransferLog[]> => {
    const history = storageService.getItem<any[]>(HISTORY_KEY, initialHistory);
    const parsedHistory = history.map(h => ({...h, date: new Date(h.date)}));
    return mockAsync(parsedHistory);
};

const addTransfer = async (newLog: TransferLog): Promise<void> => {
    const logWithId = {
        ...newLog,
        id: newLog.id || generateId()
    };
    const history = storageService.getItem<TransferLog[]>(HISTORY_KEY, initialHistory);
    const updatedHistory = [logWithId, ...history];
    storageService.setItem(HISTORY_KEY, updatedHistory);
    return mockAsync(undefined);
};

const updateTransfer = async (updatedLog: TransferLog): Promise<void> => {
    const history = storageService.getItem<TransferLog[]>(HISTORY_KEY, initialHistory);
    const updatedHistory = history.map(log => log.id === updatedLog.id ? updatedLog : log);
    storageService.setItem(HISTORY_KEY, updatedHistory);
    return mockAsync(undefined);
}

export const transferService = {
    getTransferHistory,
    addTransfer,
    updateTransfer,
};

import { User, ID } from '../types';
import { storageService } from './storageService';
import { users as mockUsers } from '../data/users';
import { generateId } from '../utils/idGenerator';

const USERS_KEY = 'users';

const mockAsync = <T>(data: T): Promise<T> => {
    return new Promise((resolve) => setTimeout(() => resolve(data), 50));
};

const getUsers = async (): Promise<User[]> => {
    return mockAsync(storageService.getItem<User[]>(USERS_KEY, mockUsers));
};

const saveUser = async (user: Omit<User, 'id'> | User): Promise<User> => {
    const users = storageService.getItem<User[]>(USERS_KEY, mockUsers);
    let savedUser: User;
    if ('id' in user) {
        const updatedUsers = users.map(u => (u.id === user.id ? user : u));
        storageService.setItem(USERS_KEY, updatedUsers);
        savedUser = user;
    } else {
        const newUser: User = {
            ...user,
            id: generateId(),
        };
        const updatedUsers = [...users, newUser];
        storageService.setItem(USERS_KEY, updatedUsers);
        savedUser = newUser;
    }
    return mockAsync(savedUser);
};

const deleteUser = async (id: ID): Promise<void> => {
    let users = storageService.getItem<User[]>(USERS_KEY, mockUsers);
    users = users.filter(u => u.id !== id);
    storageService.setItem(USERS_KEY, users);
    return mockAsync(undefined);
};

export const userService = {
    getUsers,
    saveUser,
    deleteUser,
};

