import { Permission } from '../types';

interface SidebarProps {
    activePage: Page;
    setActivePage: (page: Page) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activePage, setActivePage }) => {
    const { currentUser, logout } = useAuth();

    const allMenuItems: Page[] = ['Dashboard', 'Vinhos', 'Movimentar Vinhos', 'Stock', 'Histórico', 'Relatórios', 'Usuários'];

    const getVisibleMenuItems = (): Page[] => {
        if (!currentUser) return [];
        switch (currentUser.role) {
            case 'Supervisor':
                return allMenuItems;
            case 'Operador':
                // Operators see Dashboard plus their permitted pages
                return ['Dashboard', ...allMenuItems.filter(item => currentUser.permissions?.includes(item as Permission))];
            case 'Visitante':
                return ['Vinhos'];
            case 'Quinta':
                 return ['Dashboard', 'Vinhos', 'Movimentar Vinhos'];
            default:
                return [];
        }
    };

    const visibleMenuItems = getVisibleMenuItems();

    // If the current active page is not in the visible items, default to the first visible item
    if (currentUser && !visibleMenuItems.includes(activePage)) {
        if (currentUser.role === 'Visitante') {
            setActivePage('Vinhos');
        } else {
            setActivePage('Dashboard');
        }
    }

    return (
        <aside className="w-64 flex-shrink-0 bg-sky-50 border-r flex flex-col">
            <div className="h-16 flex items-center justify-center text-2xl font-bold text-sky-800 border-b border-sky-200">
                <span>Vinho Stock</span>
            </div>
            <nav className="mt-4 flex-grow">
                <ul>
                    {visibleMenuItems.map(item => (
                        <li key={item}>
                            <a
                                href="#"
                                onClick={(e) => {
                                    e.preventDefault();
                                    setActivePage(item);
                                }}
                                className={`flex items-center px-6 py-3 text-gray-700 hover:bg-sky-100 hover:text-sky-700 ${
                                    activePage === item ? 'bg-sky-200 text-sky-800 font-semibold' : ''
                                }`}
                            >
                                <span className="ml-3">{item}</span>
                            </a>
                        </li>
                    ))}
                </ul>
            </nav>
            <div className="p-4 border-t border-sky-100">
                <button
                    onClick={logout}
                    className="w-full px-4 py-2 text-sm text-sky-700 bg-sky-100 rounded-md hover:bg-sky-200 focus:outline-none"
                >
                    Sair
                </button>
            </div>
        </aside>
    );
};

export default Sidebar;

import React, { useState, useMemo } from 'react';
import { StockItem, ID } from '../types';
import AddWineModal from './AddWineModal';
import AdjustStockModal from './AdjustStockModal';
import { useAuth } from '../contexts/AuthContext';

interface StockProps {
  stock: StockItem[];
  onAddWine: (newWine: Omit<StockItem, 'id'>) => void;
  onDeleteWine: (id: ID) => void;
  onAddStockQuantity: (id: ID, quantity: number) => void;
  onRemoveStockQuantity: (id: ID, quantity: number) => void;
}

const Stock: React.FC<StockProps> = ({ stock, onAddWine, onDeleteWine, onAddStockQuantity, onRemoveStockQuantity }) => {
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isAdjustModalOpen, setIsAdjustModalOpen] = useState(false);
  const [selectedWine, setSelectedWine] = useState<StockItem | null>(null);
  const { currentUser } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneralStockExpanded, setIsGeneralStockExpanded] = useState(false);

  const canAddWine = currentUser?.role === 'Supervisor' || 
                     (currentUser?.role === 'Operador' && currentUser.permissions?.includes('Stock'));

  const canDeleteWine = currentUser?.role === 'Supervisor';

  const generalStock = stock.filter(item => !item.quintaName);
  const quintaStock = stock.filter(item => item.quintaName);

  // Quantidade de vinhos (rótulos) únicos cadastrados no sistema (base)
  const totalLabelsRegistered = generalStock.length;

  const filterStock = (data: StockItem[]) => {
    if (!searchTerm) return data;
    const term = searchTerm.toLowerCase();
    return data.filter(item => 
      item.brand.toLowerCase().includes(term) ||
      item.wineName.toLowerCase().includes(term)
    );
  };

  const quintaStockSummary = useMemo(() => {
    const summary: { [key: string]: number } = {};

    quintaStock.forEach(item => {
        if (item.quintaName) {
            if (summary[item.quintaName]) {
                summary[item.quintaName] += item.quantity;
            } else {
                summary[item.quintaName] = item.quantity;
            }
        }
    });

    return Object.entries(summary).map(([quintaName, totalQuantity]) => ({
        quintaName,
        totalQuantity
    })).sort((a, b) => a.quintaName.localeCompare(b.quintaName));

  }, [quintaStock]);

  // Vinhos com stock baixo especificamente nas quintas
  const lowStockInQuintas = useMemo(() => {
    return quintaStock.filter(item => item.quantity > 0 && item.quantity <= 6);
  }, [quintaStock]);


  const filteredGeneralStock = filterStock(generalStock);
  const generalStockToShow = isGeneralStockExpanded ? filteredGeneralStock : filteredGeneralStock.slice(0, 5);

  const handleOpenAdjustModal = (item: StockItem) => {
    setSelectedWine(item);
    setIsAdjustModalOpen(true);
  };


  return (
    <>
      <div className="bg-white p-8 rounded-xl shadow-sm">
        <div className="flex flex-col md:flex-row justify-between md:items-center mb-6 gap-4">
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-bold text-gray-800">Gestão de Stock</h2>
            <span className="bg-purple-100 text-purple-700 text-xs font-bold px-2.5 py-1 rounded-full border border-purple-200 shadow-sm" title="Total de rótulos diferentes cadastrados no sistema">
                {totalLabelsRegistered} vinhos cadastrados
            </span>
          </div>
          {canAddWine && (
            <button
              onClick={() => setIsAddModalOpen(true)}
              className="px-4 py-2 bg-purple-600 text-white rounded-md hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500 transition-colors shadow-sm"
            >
              Adicionar Vinho
            </button>
          )}
        </div>

        {/* Estoque Geral - Detailed List */}
        <div className="mb-10">
            <h3 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                Stock Geral
                <span className="text-xs font-normal text-gray-400">(Vinhos em armazém central)</span>
            </h3>

            <div className="mb-6">
                <div className="relative max-w-lg">
                    <input 
                        type="text"
                        placeholder="Pesquisar por marca ou nome no Stock Geral..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 shadow-sm"
                    />
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <svg className="h-5 w-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                        </svg>
                    </div>
                </div>
            </div>

            <div className="overflow-x-auto rounded-lg border border-gray-100">
                <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                    <tr>
                        <th scope="col" className="px-6 py-3">Marca</th>
                        <th scope="col" className="px-6 py-3">Nome do Vinho</th>
                        <th scope="col" className="px-6 py-3">Tipo</th>
                        <th scope="col" className="px-6 py-3 text-right">Quantidade</th>
                        {canDeleteWine && <th scope="col" className="px-6 py-3 text-center">Ações</th>}
                    </tr>
                    </thead>
                    <tbody>
                    {generalStockToShow.map((item) => (
                        <tr key={item.id} className="bg-white border-b hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-4 font-medium text-gray-900">{item.brand}</td>
                          <td className="px-6 py-4">{item.wineName}</td>
                          <td className="px-6 py-4">{item.wineType}</td>
                          <td className="px-6 py-4 text-right font-bold text-gray-800">{item.quantity}</td>
                          {canDeleteWine && (
                            <td className="px-6 py-4 text-center space-x-4">
                                <button 
                                    onClick={() => handleOpenAdjustModal(item)}
                                    className="font-medium text-purple-600 hover:text-purple-800 transition-colors"
                                >
                                    Ajustar
                                </button>
                                <button 
                                    onClick={() => {
                                        if (window.confirm(`Tem certeza que deseja excluir o vinho ${item.brand} - ${item.wineName} do stock geral? Esta ação não pode ser desfeita.`)) {
                                            onDeleteWine(item.id);
                                        }
                                    }}
                                    className="font-medium text-red-600 hover:text-red-800 transition-colors"
                                >
                                    Excluir
                                </button>
                            </td>
                          )}
                        </tr>
                    ))}
                    </tbody>
                </table>
                {filteredGeneralStock.length === 0 && <p className="text-center text-gray-500 py-10 italic bg-gray-50">Nenhum vinho encontrado com este termo.</p>}
            </div>

            {filteredGeneralStock.length > 5 && (
              <div className="text-center mt-4">
                <button
                  onClick={() => setIsGeneralStockExpanded(!isGeneralStockExpanded)}
                  className="px-4 py-2 text-sm text-purple-600 font-semibold rounded-md hover:bg-purple-50 focus:outline-none transition-colors"
                >
                  {isGeneralStockExpanded ? 'Ocultar vinhos extras ↑' : `Ver todos os ${filteredGeneralStock.length} vinhos ↓`}
                </button>
              </div>
            )}
        </div>

        {/* Estoque nas Quintas - Summary */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div>
                <h3 className="text-xl font-bold text-gray-700 mb-4">Stock Total por Quinta</h3>
                 <div className="overflow-x-auto rounded-lg border border-gray-100 shadow-sm">
                    <table className="w-full text-sm text-left text-gray-500">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                        <tr>
                            <th scope="col" className="px-6 py-3">Localização</th>
                            <th scope="col" className="px-6 py-3 text-right">Garrafas em Stock</th>
                        </tr>
                        </thead>
                        <tbody>
                        {quintaStockSummary.map((item) => (
                            <tr key={item.quintaName} className="bg-white border-b hover:bg-gray-50 transition-colors">
                                <td className="px-6 py-4 font-medium text-gray-800">{item.quintaName}</td>
                                <td className="px-6 py-4 text-right font-bold text-purple-700 text-lg">{item.totalQuantity}</td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                    {quintaStockSummary.length === 0 && <p className="text-center text-gray-500 py-6 italic">Nenhum stock distribuído nas quintas.</p>}
                </div>
            </div>

            {/* Nova seção: Alertas de Stock Baixo nas Quintas */}
            <div>
                <h3 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                    Alertas Críticos nas Quintas
                    <span className="text-xs bg-orange-100 text-orange-600 px-1.5 py-0.5 rounded">≤ 6 garrafas</span>
                </h3>
                {lowStockInQuintas.length > 0 ? (
                    <div className="space-y-3">
                        {lowStockInQuintas.map(item => (
                            <div key={item.id} className="flex items-center justify-between p-3 bg-orange-50 border border-orange-100 rounded-lg shadow-sm">
                                <div>
                                    <p className="text-sm font-bold text-orange-900">{item.brand} - {item.wineName}</p>
                                    <p className="text-xs text-orange-700">{item.quintaName}</p>
                                </div>
                                <div className="text-right">
                                    <span className="text-lg font-black text-orange-600">{item.quantity}</span>
                                    <span className="text-xs text-orange-500 ml-1">un.</span>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="p-10 border-2 border-dashed border-gray-100 rounded-xl flex flex-col items-center justify-center text-gray-400">
                        <svg className="h-10 w-10 mb-2 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                        <p className="text-sm font-medium">Stock saudável em todas as quintas.</p>
                    </div>
                )}
            </div>
        </div>
      </div>

      {canAddWine && (
        <AddWineModal
            isOpen={isAddModalOpen}
            onClose={() => setIsAddModalOpen(false)}
            onAddWine={onAddWine}
        />
      )}
      {canDeleteWine && (
        <AdjustStockModal
            isOpen={isAdjustModalOpen}
            onClose={() => setIsAdjustModalOpen(false)}
            wine={selectedWine}
            onAddQuantity={onAddStockQuantity}
            onRemoveQuantity={onRemoveStockQuantity}
        />
      )}
    </>
  );
};

export default Stock;

import { StockItem, ID } from '../types';
import { storageService } from './storageService';
import { initialStock } from '../data/wines';
import { generateId } from '../utils/idGenerator';

const STOCK_KEY = 'stock';

const mockAsync = <T>(data: T): Promise<T> => {
    return new Promise((resolve) => setTimeout(() => resolve(data), 50));
};

const getStock = async (): Promise<StockItem[]> => {
    return mockAsync(storageService.getItem<StockItem[]>(STOCK_KEY, initialStock));
};

const saveStockLocal = (stock: StockItem[]): void => {
    storageService.setItem(STOCK_KEY, stock);
};

const addWine = async (newWine: Omit<StockItem, 'id'>): Promise<StockItem> => {
    const newStockItem: StockItem = {
        ...newWine,
        id: generateId(),
    };
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const updatedStock = [...stock, newStockItem];
    saveStockLocal(updatedStock);
    return mockAsync(newStockItem);
};

const updateItem = async (item: StockItem): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const updatedStock = stock.map(s => s.id === item.id ? item : s);
    saveStockLocal(updatedStock);
    return mockAsync(undefined);
};

const updateStock = async (updatedStock: StockItem[]): Promise<void> => {
    saveStockLocal(updatedStock);
    return mockAsync(undefined);
};

const deleteWine = async (id: ID): Promise<void> => {
    let stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    stock = stock.filter(item => item.id !== id);
    saveStockLocal(stock);
    return mockAsync(undefined);
};

const addStockQuantity = async (id: ID, quantityToAdd: number): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const itemIndex = stock.findIndex(item => item.id === id);
    if (itemIndex > -1) {
        stock[itemIndex].quantity += quantityToAdd;
        saveStockLocal(stock);
    }
    return mockAsync(undefined);
};

const removeStockQuantity = async (id: ID, quantityToRemove: number): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const itemIndex = stock.findIndex(item => item.id === id);
    if (itemIndex > -1) {
        const newQuantity = stock[itemIndex].quantity - quantityToRemove;
        stock[itemIndex].quantity = Math.max(0, newQuantity);
        saveStockLocal(stock);
    }
    return mockAsync(undefined);
};

const toggleLowStockAlert = async (id: ID, status: boolean): Promise<void> => {
    const stock = storageService.getItem<StockItem[]>(STOCK_KEY, initialStock);
    const itemIndex = stock.findIndex(item => item.id === id);
    if (itemIndex > -1) {
        stock[itemIndex].lowStockAlert = status;
        saveStockLocal(stock);
    }
    return mockAsync(undefined);
};

export const stockService = {
    getStock,
    addWine,
    updateItem,
    updateStock,
    deleteWine,
    addStockQuantity,
    removeStockQuantity,
    toggleLowStockAlert,
};

import React, { useState, useEffect } from 'react';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import Login from './components/Login';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Vinhos from './components/Vinhos';
import Stock from './components/Stock';
import Transferir from './components/Transferir';
import Historico from './components/Historico';
import Relatorios from './components/Relatorios';
import Usuarios from './components/Usuarios';
import Footer from './components/Footer';

import { stockService } from './services/stockService';
import { transferService } from './services/transferService';
import { userService } from './services/userService';
import { generateId } from './utils/idGenerator';

import { StockItem, TransferLog, User, ID } from './types';

export type Page = 'Dashboard' | 'Vinhos' | 'Stock' | 'Movimentar Vinhos' | 'Histórico' | 'Relatórios' | 'Usuários';

const AppContent: React.FC = () => {
  const { currentUser, users, setUsers } = useAuth();
  const [activePage, setActivePage] = useState<Page>('Dashboard');

  const [stock, setStock] = useState<StockItem[]>([]);
  const [transferHistory, setTransferHistory] = useState<TransferLog[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Load data from services on initial render
  const refreshData = async () => {
      setIsLoading(true);
      try {
        const [loadedStock, loadedHistory] = await Promise.all([
            stockService.getStock(),
            transferService.getTransferHistory()
        ]);
        setStock(loadedStock);
        setTransferHistory(loadedHistory);
      } catch (error) {
          console.error("Failed to load data", error);
      } finally {
          setIsLoading(false);
      }
  };

  useEffect(() => {
    if (currentUser) {
        refreshData();
    }
  }, [currentUser]);


  if (!currentUser) {
    return <Login />;
  }

  const pendingTransfers = transferHistory.filter(t => t.status === 'Pendente');

  const handleAddWine = async (newWine: Omit<StockItem, 'id'>) => {
    await stockService.addWine(newWine);
    // Refresh to get new ID and updated state
    const updatedStock = await stockService.getStock();
    setStock(updatedStock);
  };

  const handleTransfer = async (transferLog: Omit<TransferLog, 'id' | 'date' | 'status'>) => {
      const canAutoApprove = currentUser?.role === 'Supervisor' || 
                             (currentUser?.role === 'Operador' && currentUser.permissions?.includes('Aprovar'));

      const status = currentUser?.role === 'Quinta' ? 'Pendente' : (canAutoApprove ? 'Aprovado' : 'Pendente');

      const newLog: TransferLog = {
          ...transferLog,
          id: generateId(), 
          date: new Date(),
          status: status,
      };

      if (status === 'Aprovado') {
          newLog.approverName = currentUser?.name;
      }

      await transferService.addTransfer(newLog);

      // Update history state
      const updatedHistory = await transferService.getTransferHistory();
      setTransferHistory(updatedHistory);

      if (status === 'Aprovado') {
          await updateStockForTransfer(newLog);
      }
  };

  const updateStockForTransfer = async (log: TransferLog) => {
      const sourceIdentifier = log.fromQuinta === 'Stock Geral' ? undefined : log.fromQuinta;
      const destIdentifier = log.toQuinta === 'Stock Geral' ? undefined : log.toQuinta;

      // 1. Handle Source (Decrement)
      if (log.fromQuinta !== 'Ajuste de Stock') {
          const sourceItem = stock.find(s => 
              s.brand === log.brand &&
              s.wineName === log.wineName &&
              s.quintaName === sourceIdentifier
          );

          if (sourceItem) {
              const updatedSource = { ...sourceItem, quantity: Math.max(0, sourceItem.quantity - log.quantity) };
              await stockService.updateItem(updatedSource);
          }
      }

      // 2. Handle Destination (Increment)
      if (log.toQuinta !== 'Consumo') {
          const destItem = stock.find(s => 
              s.brand === log.brand &&
              s.wineName === log.wineName &&
              s.quintaName === destIdentifier
          );

          if (destItem) {
              const updatedDest = { ...destItem, quantity: destItem.quantity + log.quantity };
              await stockService.updateItem(updatedDest);
          } else {
              const originalWine = stock.find(s => s.brand === log.brand && s.wineName === log.wineName);
              await stockService.addWine({
                  brand: log.brand,
                  wineName: log.wineName,
                  wineType: originalWine?.wineType || 'Tinto',
                  quantity: log.quantity,
                  quintaName: destIdentifier,
                  lowStockAlert: originalWine?.lowStockAlert || false,
              });
          }
      }

      const freshStock = await stockService.getStock();
      setStock(freshStock);
  };

  const handleApproval = async (id: ID, newStatus: 'Aprovado' | 'Reprovado') => {
      const transferToProcess = transferHistory.find(log => log.id === id);

      if (transferToProcess) {
          const updatedTransfer = { ...transferToProcess, status: newStatus };
          if (newStatus === 'Aprovado') {
            updatedTransfer.approverName = currentUser?.name;
          }

          await transferService.updateTransfer(updatedTransfer);

          const updatedHistory = await transferService.getTransferHistory();
          setTransferHistory(updatedHistory);

          if (newStatus === 'Aprovado') {
              await updateStockForTransfer(updatedTransfer);
          }
      }
  };

  const handleSaveUser = async (user: Omit<User, 'id'> | User) => {
    await userService.saveUser(user);
    const updatedUsers = await userService.getUsers();
    setUsers(updatedUsers);
  };

  const handleDeleteUser = async (id: ID) => {
      if (currentUser.id === id) {
          alert("Você não pode deletar seu próprio usuário.");
          return;
      }
      await userService.deleteUser(id);
      const updatedUsers = await userService.getUsers();
      setUsers(updatedUsers);
  }

  const handleDeleteWine = async (id: ID) => {
      if (currentUser?.role !== 'Supervisor') {
          alert("Apenas supervisores podem excluir vinhos.");
          return;
      }

      const wineToDelete = stock.find(item => item.id === id);

      if (!wineToDelete) {
          alert("Vinho não encontrado.");
          return;
      }

      if (wineToDelete.quantity > 0) {
          alert(`Não é possível excluir o vinho "${wineToDelete.brand} - ${wineToDelete.wineName}" pois ainda existem ${wineToDelete.quantity} garrafas no Stock Geral. Ajuste a quantidade para 0 antes de excluir.`);
          return;
      }

      const isInQuintaStock = stock.some(item => 
          item.brand === wineToDelete.brand &&
          item.wineName === wineToDelete.wineName &&
          item.quintaName 
      );

      if (isInQuintaStock) {
          alert(`Este vinho não pode ser excluído pois ainda existe stock em uma ou mais quintas. Transfira todo o stock para o "Stock Geral" e zere a quantidade antes de excluir.`);
          return;
      }

      await stockService.deleteWine(id);
      const updatedStock = await stockService.getStock();
      setStock(updatedStock); 
  };

  const handleAddStockQuantity = async (id: ID, quantityToAdd: number) => {
    if (currentUser?.role !== 'Supervisor') {
        alert("Apenas supervisores podem ajustar o stock.");
        return;
    }
    await stockService.addStockQuantity(id, quantityToAdd);
    const updatedStock = await stockService.getStock();
    setStock(updatedStock); 
  };

  const handleRemoveStockQuantity = async (id: ID, quantityToRemove: number) => {
    if (currentUser?.role !== 'Supervisor') {
        alert("Apenas supervisores podem ajustar o stock.");
        return;
    }
    await stockService.removeStockQuantity(id, quantityToRemove);
    const updatedStock = await stockService.getStock();
    setStock(updatedStock); 
  };

  const handleUpdateLowStockAlert = async (id: ID, status: boolean) => {
    if (currentUser?.role !== 'Supervisor') {
        alert("Apenas supervisores podem ajustar o stock.");
        return;
    }
    await stockService.toggleLowStockAlert(id, status);
    const updatedStock = await stockService.getStock();
    setStock(updatedStock); 
  };


  const renderPage = () => {
    if (isLoading) {
        return (
            <div className="flex h-full items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600"></div>
                <span className="ml-3 text-gray-600">Carregando dados...</span>
            </div>
        );
    }

    switch (activePage) {
      case 'Dashboard':
        return <Dashboard 
                  stock={stock} 
                  transferHistory={transferHistory} 
                  pendingTransfers={pendingTransfers}
                  onApprove={(id) => handleApproval(id, 'Aprovado')}
                  onReject={(id) => handleApproval(id, 'Reprovado')}
                />;
      case 'Vinhos':
        return <Vinhos stock={stock} />;
      case 'Stock':
        return <Stock 
                  stock={stock} 
                  onAddWine={handleAddWine} 
                  onDeleteWine={handleDeleteWine} 
                  onAddStockQuantity={handleAddStockQuantity} 
                  onRemoveStockQuantity={handleRemoveStockQuantity}
                  onUpdateLowStockAlert={handleUpdateLowStockAlert}
                />;
      case 'Movimentar Vinhos':
        return <Transferir stock={stock} onTransfer={handleTransfer} />;
      case 'Histórico':
        return <Historico transferHistory={transferHistory} />;
      case 'Relatórios':
        return <Relatorios stock={stock} transferHistory={transferHistory} />;
      case 'Usuários':
        return <Usuarios users={users} onSaveUser={handleSaveUser} onDeleteUser={handleDeleteUser} />;
      default:
        return <Dashboard 
                  stock={stock} 
                  transferHistory={transferHistory}
                  pendingTransfers={pendingTransfers}
                  onApprove={(id) => handleApproval(id, 'Aprovado')}
                  onReject={(id) => handleApproval(id, 'Reprovado')}
                />;
    }
  };

  return (
    <div className="flex h-screen bg-green-50 font-sans">
      <Sidebar activePage={activePage} setActivePage={setActivePage} />
      <div className="flex-1 flex flex-col overflow-hidden">
        <Header />
        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-green-50 p-6">
          {renderPage()}
        </main>
        <Footer />
      </div>
    </div>
  );
};

