                                <div>
                                    <p className="text-sm font-bold text-red-900">{item.brand} - {item.wineName}</p>
                                    <p className="text-xs text-red-700">{item.quintaName}</p>
                                </div>
                                <div className="text-right">
                                    <span className="text-lg font-black text-red-600">{item.quantity}</span>
                                    <span className="text-xs text-red-500 ml-1">un.</span>
                                </div>
