import React, { useState, useEffect } from 'react';
import { StockItem, ID } from '../types';

interface AdjustStockModalProps {
    isOpen: boolean;
    onClose: () => void;
    wine: StockItem | null;
    onAddQuantity: (id: ID, quantity: number) => void;
    onRemoveQuantity: (id: ID, quantity: number) => void;
    onUpdateLowStockAlert: (id: ID, status: boolean) => void;
}

const AdjustStockModal: React.FC<AdjustStockModalProps> = ({ 
    isOpen, 
    onClose, 
    wine, 
    onAddQuantity, 
    onRemoveQuantity,
    onUpdateLowStockAlert
}) => {
    const [quantityToAdd, setQuantityToAdd] = useState<number | ''>('');
    const [quantityToRemove, setQuantityToRemove] = useState<number | ''>('');
    const [error, setError] = useState('');

    useEffect(() => {
        if (isOpen) {
            setQuantityToAdd('');
            setQuantityToRemove('');
            setError('');
        }
    }, [isOpen]);

    if (!isOpen || !wine) return null;

    const handleAdd = () => {
        setError('');
        const numQuantity = Number(quantityToAdd);
        if (!quantityToAdd || numQuantity <= 0) {
            setError('Por favor, insira uma quantidade válida para adicionar.');
            return;
        }
        onAddQuantity(wine.id, numQuantity);
        onClose();
    };

    const handleRemove = () => {
        setError('');
        const numQuantity = Number(quantityToRemove);
        if (!quantityToRemove || numQuantity <= 0) {
            setError('Por favor, insira uma quantidade válida para remover.');
            return;
        }
        if (numQuantity > wine.quantity) {
            setError(`A quantidade a remover não pode ser maior que o stock atual (${wine.quantity}).`);
            return;
        }
        onRemoveQuantity(wine.id, numQuantity);
        onClose();
    };

    const handleToggleAlert = () => {
        onUpdateLowStockAlert(wine.id, !wine.lowStockAlert);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4">
            <div className="bg-white p-6 md:p-8 rounded-2xl shadow-2xl w-full max-w-md border border-slate-100">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold text-slate-800">Ajustar Stock</h2>
                    <button 
                        onClick={handleToggleAlert}
                        title={wine.lowStockAlert ? "Desativar alerta visual de stock baixo" : "Ativar alerta visual de stock baixo"}
                        className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-[10px] font-bold uppercase transition-all shadow-sm ${
                            wine.lowStockAlert 
                                ? 'bg-red-500 border-red-600 text-white' 
                                : 'bg-slate-100 border-slate-200 text-slate-400'
                        }`}
                    >
                        <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 20 20">
                            <path d="M10 2a6 6 0 00-6 6v3.586l-.707.707A1 1 0 004 14h12a1 1 0 00.707-1.707L16 11.586V8a6 6 0 00-6-6zM10 18a3 3 0 01-3-3h6a3 3 0 01-3 3z" />
                        </svg>
                        {wine.lowStockAlert ? 'Alerta Ativado' : 'Alerta Desativado'}
                    </button>
                </div>

                <div className="bg-slate-50 p-4 rounded-xl mb-6">
                    <p className="text-xs text-slate-500 uppercase font-semibold tracking-wider mb-1">{wine.brand}</p>
                    <p className="text-lg font-bold text-slate-900 leading-tight">{wine.wineName}</p>
                    <div className="mt-3 pt-3 border-t border-slate-200 flex justify-between items-center">
                        <span className="text-sm text-slate-600 font-medium">Stock Atual</span>
                        <span className={`text-2xl font-black ${wine.lowStockAlert && wine.quantity <= 6 ? 'text-red-600' : 'text-purple-600'}`}>
                            {wine.quantity}
                        </span>
                    </div>
                </div>

                <div className="space-y-5">
                    <div>
                        <label htmlFor="quantityToAdd" className="block text-xs font-bold text-slate-500 uppercase mb-2">Entrada de Garrafas (+)</label>
                         <div className="flex gap-2">
                             <input
                                type="number"
                                id="quantityToAdd"
                                value={quantityToAdd}
                                onChange={(e) => setQuantityToAdd(e.target.value === '' ? '' : Number(e.target.value))}
                                className="block w-full px-4 py-2.5 bg-white border border-slate-200 rounded-xl shadow-inner focus:outline-none focus:ring-2 focus:ring-green-500 text-slate-800"
                                placeholder="Quantidade"
                                min="1"
                            />
                            <button
                                onClick={handleAdd}
                                className="px-5 py-2.5 bg-green-600 text-white font-bold rounded-xl hover:bg-green-700 transition-colors shadow-md active:scale-95"
                            >
                                Inserir
                            </button>
                         </div>
                    </div>

                    <div>
                        <label htmlFor="quantityToRemove" className="block text-xs font-bold text-slate-500 uppercase mb-2">Saída de Garrafas (-)</label>
                        <div className="flex gap-2">
                            <input
                                type="number"
                                id="quantityToRemove"
                                value={quantityToRemove}
                                onChange={(e) => setQuantityToRemove(e.target.value === '' ? '' : Number(e.target.value))}
                                className="block w-full px-4 py-2.5 bg-white border border-slate-200 rounded-xl shadow-inner focus:outline-none focus:ring-2 focus:ring-red-500 text-slate-800"
                                placeholder="Quantidade"
                                min="1"
                                max={wine.quantity}
                            />
                            <button
                                onClick={handleRemove}
                                className="px-5 py-2.5 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-900 transition-colors shadow-md active:scale-95"
                            >
                                Retirar
                            </button>
                        </div>
                    </div>

                    {error && <p className="text-xs text-red-500 font-bold bg-red-50 p-2 rounded-lg text-center border border-red-100">{error}</p>}
                </div>

                <div className="mt-8">
                    <button
                        type="button"
                        onClick={onClose}
                        className="w-full px-6 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors border border-slate-200"
                    >
                        Voltar
                    </button>
                </div>
            </div>
        </div>
    );
};

export default AdjustStockModal;

import React, { useState, useMemo } from 'react';
import { StockItem, ID } from '../types';
import AddWineModal from './AddWineModal';
import AdjustStockModal from './AdjustStockModal';
import { useAuth } from '../contexts/AuthContext';

interface StockProps {
  stock: StockItem[];
  onAddWine: (newWine: Omit<StockItem, 'id'>) => void;
  onDeleteWine: (id: ID) => void;
  onAddStockQuantity: (id: ID, quantity: number) => void;
  onRemoveStockQuantity: (id: ID, quantity: number) => void;
  onUpdateLowStockAlert: (id: ID, status: boolean) => void;
}

const Stock: React.FC<StockProps> = ({ 
  stock, 
  onAddWine, 
  onDeleteWine, 
  onAddStockQuantity, 
  onRemoveStockQuantity,
  onUpdateLowStockAlert
}) => {
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isAdjustModalOpen, setIsAdjustModalOpen] = useState(false);
  const [selectedWineId, setSelectedWineId] = useState<ID | null>(null);
  const { currentUser } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [isGeneralStockExpanded, setIsGeneralStockExpanded] = useState(false);

  const canAddWine = currentUser?.role === 'Supervisor' || 
                     (currentUser?.role === 'Operador' && currentUser.permissions?.includes('Stock'));

  const canDeleteWine = currentUser?.role === 'Supervisor';

  const generalStock = stock.filter(item => !item.quintaName);
  const quintaStock = stock.filter(item => item.quintaName);

  const filterStock = (data: StockItem[]) => {
    if (!searchTerm) return data;
    const term = searchTerm.toLowerCase();
    return data.filter(item => 
      item.brand.toLowerCase().includes(term) ||
      item.wineName.toLowerCase().includes(term)
    );
  };

  const quintaStockSummary = useMemo(() => {
    const summary: { [key: string]: number } = {};

    quintaStock.forEach(item => {
        if (item.quintaName) {
            if (summary[item.quintaName]) {
                summary[item.quintaName] += item.quantity;
            } else {
                summary[item.quintaName] = item.quantity;
            }
        }
    });

    return Object.entries(summary).map(([quintaName, totalQuantity]) => ({
        quintaName,
        totalQuantity
    })).sort((a, b) => a.quintaName.localeCompare(b.quintaName));

  }, [quintaStock]);

  const lowStockInQuintas = useMemo(() => {
    return quintaStock.filter(item => item.lowStockAlert && item.quantity > 0 && item.quantity <= 6);
  }, [quintaStock]);


  const filteredGeneralStock = filterStock(generalStock);
  const generalStockToShow = isGeneralStockExpanded ? filteredGeneralStock : filteredGeneralStock.slice(0, 5);

  const handleOpenAdjustModal = (item: StockItem) => {
    setSelectedWineId(item.id);
    setIsAdjustModalOpen(true);
  };

  const selectedWine = useMemo(() => {
    if (selectedWineId === null) return null;
    return stock.find(s => s.id === selectedWineId) || null;
  }, [stock, selectedWineId]);


  return (
    <>
      <div className="bg-white p-8 rounded-xl shadow-sm">
        <div className="flex flex-col md:flex-row justify-between md:items-center mb-6 gap-4">
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-bold text-gray-800">Gestão de Stock</h2>
          </div>
          {canAddWine && (
            <button
              onClick={() => setIsAddModalOpen(true)}
              className="px-4 py-2 bg-purple-600 text-white rounded-md hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500 transition-colors shadow-sm"
            >
              Adicionar Vinho
            </button>
          )}
        </div>

        <div className="mb-10">
            <h3 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                Stock Geral
                <span className="text-xs font-normal text-gray-400">(Vinhos em armazém central)</span>
            </h3>

            <div className="mb-6">
                <div className="relative max-w-lg">
                    <input 
                        type="text"
                        placeholder="Pesquisar por marca ou nome no Stock Geral..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 shadow-sm text-sm"
                    />
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <svg className="h-5 w-5 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                        </svg>
                    </div>
                </div>
            </div>

            <div className="overflow-x-auto rounded-lg border border-gray-100">
                <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                    <tr>
                        <th scope="col" className="px-6 py-3">Marca</th>
                        <th scope="col" className="px-6 py-3">Nome do Vinho</th>
                        <th scope="col" className="px-6 py-3">Tipo</th>
                        <th scope="col" className="px-6 py-3 text-right">Quantidade</th>
                        <th scope="col" className="px-6 py-3 text-center">Alerta</th>
                        {canDeleteWine && <th scope="col" className="px-6 py-3 text-center">Ações</th>}
                    </tr>
                    </thead>
                    <tbody>
                    {generalStockToShow.map((item) => (
                        <tr key={item.id} className="bg-white border-b hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-4 font-medium text-gray-900">{item.brand}</td>
                          <td className="px-6 py-4">{item.wineName}</td>
                          <td className="px-6 py-4">{item.wineType}</td>
                          <td className={`px-6 py-4 text-right font-bold ${item.lowStockAlert && item.quantity <= 6 ? 'text-red-600' : 'text-gray-800'}`}>
                            {item.quantity}
                          </td>
                          <td className="px-6 py-4 text-center">
                            {item.lowStockAlert ? (
                                <span className="text-red-600">
                                    <svg className="w-5 h-5 mx-auto" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a6 6 0 00-6 6v3.586l-.707.707A1 1 0 004 14h12a1 1 0 00.707-1.707L16 11.586V8a6 6 0 00-6-6zM10 18a3 3 0 01-3-3h6a3 3 0 01-3 3z"/></svg>
                                </span>
                            ) : (
                                <span className="text-gray-200">
                                    <svg className="w-5 h-5 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 00-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                                </span>
                            )}
                          </td>
                          {canDeleteWine && (
                            <td className="px-6 py-4 text-center space-x-3">
                                <button 
                                    onClick={() => handleOpenAdjustModal(item)}
                                    className="text-purple-600 hover:text-purple-900 font-medium"
                                >
                                    Ajustar
                                </button>
                                <button 
                                    onClick={() => onDeleteWine(item.id)}
                                    className="text-red-600 hover:text-red-900 font-medium"
                                >
                                    Excluir
                                </button>
                            </td>
                          )}
                        </tr>
                    ))}
                    </tbody>
                </table>
            </div>

            {filteredGeneralStock.length > 5 && (
                <div className="mt-4 text-center">
                    <button 
                        onClick={() => setIsGeneralStockExpanded(!isGeneralStockExpanded)}
                        className="text-sm text-purple-600 hover:text-purple-800 font-semibold"
                    >
                        {isGeneralStockExpanded ? 'Ver menos' : `Ver todos os ${filteredGeneralStock.length} rótulos`}
                    </button>
                </div>
            )}
        </div>

        <div>
            <h3 className="text-xl font-bold text-gray-700 mb-4 flex items-center gap-2">
                Stock nas Quintas
                <span className="text-xs font-normal text-gray-400">(Vinhos em locais de produção)</span>
            </h3>

            {quintaStockSummary.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    {quintaStockSummary.map(summary => (
                        <div key={summary.quintaName} className="p-4 border rounded-lg bg-gray-50 flex justify-between items-center shadow-sm">
                            <span className="font-semibold text-gray-700">{summary.quintaName}</span>
                            <span className="bg-purple-100 text-purple-700 font-bold px-2.5 py-1 rounded-full text-sm">
                                {summary.totalQuantity} garrafas
                            </span>
                        </div>
                    ))}
                </div>
            ) : (
                <p className="text-gray-500 italic text-sm">Nenhuma quinta possui stock registado.</p>
            )}

            {lowStockInQuintas.length > 0 && (
                 <div className="mt-6 p-4 border border-red-100 bg-red-50 rounded-lg">
                    <h4 className="text-red-800 font-bold text-sm mb-2 uppercase tracking-tight flex items-center gap-2">
                        Alertas em Quintas
                    </h4>
                    <div className="flex flex-wrap gap-2">
                        {lowStockInQuintas.map(item => (
                            <span key={item.id} className="text-xs font-medium text-red-700 bg-white border border-red-200 px-2 py-1 rounded">
                                {item.quintaName}: {item.brand} - {item.wineName} ({item.quantity})
                            </span>
                        ))}
                    </div>
                </div>
            )}
        </div>
      </div>

      <AddWineModal 
        isOpen={isAddModalOpen} 
        onClose={() => setIsAddModalOpen(false)} 
        onAddWine={onAddWine} 
      />

      <AdjustStockModal 
        isOpen={isAdjustModalOpen} 
        onClose={() => setIsAdjustModalOpen(false)} 
        wine={selectedWine}
        onAddQuantity={onAddStockQuantity}
        onRemoveQuantity={onRemoveStockQuantity}
        onUpdateLowStockAlert={onUpdateLowStockAlert}
      />
    </>
  );
};

